import asyncio
import websockets
from typing import Dict, List

class InventorySystem:
    def __init__(self):
        self.items = {}
        self.players = {}
    
    async def add_item(self, player_id: int, item_id: int) -> None:
        if player_id not in self.players:
            self.players[player_id] = []
        
        self.items[item_id] = {
            "owner": player_id,
            "quantity": 1
        }
    
    async def remove_item(self, player_id: int, item_id: int) -> None:
        if item_id not in self.items or self.items[item_id]["owner"] != player_id:
            return
        
        del self.items[item_id]
    
    async def transfer_item(self, from_player_id: int, to_player_id: int, item_id: int) -> None:
        if item_id not in self.items or self.items[item_id]["owner"] != from_player_id:
            return
        
        self.items[item_id]["owner"] = to_player_id
    
    async def get_inventory(self, player_id: int) -> List[Dict]:
        if player_id not in self.players:
            return []
        
        inventory = []
        for item_id, item in self.items.items():
            if item["owner"] == player_id:
                inventory.append(item)
        
        return inventory